import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it)); C = int(next(it))
        if A > B and A > C:
            out_lines.append('Alice')
        elif B > A and B > C:
            out_lines.append('Bob')
        else:
            out_lines.append('Charlie')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

